-- ============================================================
-- Open Day 1–7 for resubmission for failed students (Slot 1 & 2)
-- 
-- This does two things per student:
--   1. Resets isFinal=false + clears submitted links in dailyTasks
--   2. Inserts into unlockedDays (day 1–7) so they bypass deadlines
-- ============================================================

USE `Social_2026`;

-- ============================================================
-- STEP 1: Preview — see current submission state
-- ============================================================
SELECT
    dt.username,
    r.name,
    r.slot,
    dt.day,
    JSON_EXTRACT(dt.data, '$.isFinal') AS isFinal
FROM dailyTasks dt
JOIN registrations r ON r.username = dt.username
WHERE dt.username IN (
