-- ============================================================
-- STEP 2a: Reset Day 1 — clear isFinal, linkedinUrl, youtubeUrl
-- ============================================================
UPDATE dailyTasks
SET data = JSON_SET(
            JSON_SET(
              JSON_SET(data, '$.isFinal', false),
              '$.linkedinUrl', NULL),
            '$.youtubeUrl', NULL),
    updatedAt = CURRENT_TIMESTAMP
